  router.post("/api/subscription/sync", requireAuth, async (req: Request, res: Response) => {
    try {
      const { tier, appUserId } = req.body;
      const validTiers = ["free", "starter", "growth", "pro"];
      if (!tier || !validTiers.includes(tier)) {
        return res.status(400).json({ message: "Invalid tier" });
      }

      // Server-side verification with RevenueCat
      // Only runs when REVENUECAT_SECRET_KEY is configured and appUserId is provided
      const rcSecretKey = process.env.REVENUECAT_SECRET_KEY;
      if (rcSecretKey && appUserId) {
        try {
          const rcResp = await fetch(
            `https://api.revenuecat.com/v1/subscribers/${encodeURIComponent(appUserId)}`,
            { headers: { Authorization: `Bearer ${rcSecretKey}` } }
          );
          if (!rcResp.ok) {
            console.error("RevenueCat verification failed:", rcResp.status, "for appUserId:", appUserId);
            return res.status(400).json({ message: "Could not verify subscription with RevenueCat" });
          }
          const rcData = await rcResp.json() as any;
          const entitlements: Record<string, any> = rcData?.subscriber?.entitlements ?? {};

          const isEntitlementActive = (id: string): boolean => {
            const ent = entitlements[id];
            if (!ent) return false;
            if (!ent.expires_date) return true;
            return new Date(ent.expires_date) > new Date();
          };

          // Map RC entitlements to the highest active tier
          let verifiedTier = "free";
          if (isEntitlementActive("pro")) verifiedTier = "pro";
          else if (isEntitlementActive("growth")) verifiedTier = "growth";
          else if (isEntitlementActive("starter")) verifiedTier = "starter";

          // Client-requested tier must not exceed what RevenueCat confirms
          const tierRank: Record<string, number> = { free: 0, starter: 1, growth: 2, pro: 3 };
          if ((tierRank[tier] ?? 0) > (tierRank[verifiedTier] ?? 0)) {
            console.warn(`RC sync tier escalation blocked: requested=${tier}, verified=${verifiedTier}, appUserId=${appUserId}`);
            return res.status(403).json({ message: "Requested tier not verified by subscription provider" });
          }
        } catch (rcErr: any) {
          console.error("RevenueCat API error during sync:", rcErr.message);
          return res.status(502).json({ message: "Subscription verification temporarily unavailable" });
        }
      } else if (!rcSecretKey) {
        console.warn("REVENUECAT_SECRET_KEY not set — subscription sync proceeding without server-side verification");
      }

      const user = await updateUser(req.session.userId!, { subscriptionTier: tier });
      return res.json({ tier: user.subscriptionTier });
    } catch {
      return res.status(500).json({ message: "Sync failed" });
    }
  });

  router.post("/api/subscription/create-checkout", requireAuth, async (req: Request, res: Response) => {
    try {
      if (!getStripe()) return res.status(503).json({ message: "Stripe is not configured" });
      const user = await getUserById(req.session.userId!);
      if (!user) return res.status(401).json({ message: "Not found" });

      const plan: string = req.body.plan || "growth";
      const interval: string = req.body.interval || "monthly";

      // Already on requested plan or higher
      const tierRank: Record<string, number> = { free: 0, starter: 1, growth: 2, pro: 3 };
      const currentRank = tierRank[user.subscriptionTier] ?? 0;
      const requestedRank = tierRank[plan] ?? 2;
      if (currentRank >= requestedRank) return res.json({ alreadyPro: true });

      const PLAN_CONFIG: Record<string, { name: string; desc: string; monthlyAmount: number; annualAmount: number; trialDays: number }> = {
        starter: {
          name: "QuotePro Starter",
          desc: "20 quotes/month, Good/Better/Best quoting, CRM basics, branded intake forms",
          monthlyAmount: 1900,
          annualAmount: 1900 * 12,
          trialDays: 0,
        },
        growth: {
          name: "QuotePro Growth",
          desc: "Unlimited quotes, AI tools, smart upsells, follow-up automations, full CRM, revenue dashboard",
          monthlyAmount: 4900,
          annualAmount: 49000,
          trialDays: 7,
        },
        pro: {
          name: "QuotePro Pro",
          desc: "Everything in Growth plus advanced automation, reporting, priority support, and premium capabilities",
          monthlyAmount: 9900,
          annualAmount: 99000,
          trialDays: 7,
        },
      };

      const config = PLAN_CONFIG[plan] ?? PLAN_CONFIG.growth;
      const isAnnual = interval === "annual";
      const unitAmount = isAnnual ? config.annualAmount : config.monthlyAmount;
      const recurringInterval = isAnnual ? "year" : "month";

      let stripeCustomerId = (user as any).stripeCustomerId;
      if (!stripeCustomerId) {
        const customer = await (await getStripe())!.customers.create({
          email: user.email,
          metadata: { userId: String(user.id) },
        });
        stripeCustomerId = customer.id;
        await updateUser(user.id, { stripeCustomerId: customer.id } as any);
      }

      const host = req.get("host")!;
      const protocol = host.includes("localhost") ? "http" : "https";

      // Support pre-configured Stripe Price IDs via env vars
      const PRICE_ID_MAP: Record<string, Record<string, string | undefined>> = {
        starter: { monthly: process.env.STRIPE_PRICE_STARTER_MONTHLY, annual: process.env.STRIPE_PRICE_STARTER_ANNUAL },
        growth: { monthly: process.env.STRIPE_PRICE_GROWTH_MONTHLY, annual: process.env.STRIPE_PRICE_GROWTH_ANNUAL },
        pro: { monthly: process.env.STRIPE_PRICE_PRO_MONTHLY, annual: process.env.STRIPE_PRICE_PRO_ANNUAL },
      };
      const priceId = PRICE_ID_MAP[plan]?.[interval];

      const lineItems: Stripe.Checkout.SessionCreateParams["line_items"] = priceId
        ? [{ price: priceId, quantity: 1 }]
        : [
            {
              price_data: {
                currency: "usd",
                product_data: { name: config.name, description: config.desc },
                recurring: { interval: recurringInterval },
                unit_amount: unitAmount,
              },
              quantity: 1,
            },
          ];

      const sessionParams: Stripe.Checkout.SessionCreateParams = {
        customer: stripeCustomerId,
        mode: "subscription",
        line_items: lineItems,
        success_url: `${protocol}://${host}/app/pricing/success?session_id={CHECKOUT_SESSION_ID}`,
        cancel_url: `${protocol}://${host}/app/pricing/cancel`,
        subscription_data: {
          metadata: { userId: String(user.id), plan, interval },
          ...(config.trialDays > 0 ? { trial_period_days: config.trialDays } : {}),
        },
        metadata: { plan, interval },
        allow_promotion_codes: true,
      };

      const session = await (await getStripe())!.checkout.sessions.create(sessionParams);
      return res.json({ url: session.url });
    } catch (error: any) {
      console.error("Subscription checkout error:", error?.message || error);
      return res.status(500).json({ message: "Failed to create checkout session" });
    }
  });

  router.get("/api/subscription/verify-session", requireAuth, async (req: Request, res: Response) => {
    try {
      if (!getStripe()) return res.status(503).json({ message: "Stripe is not configured" });
      const { session_id } = req.query as { session_id: string };
      if (!session_id) return res.status(400).json({ message: "Missing session_id" });

      const session = await (await getStripe())!.checkout.sessions.retrieve(session_id);

      const sessionUserId = session.subscription_data?.metadata?.userId
        || session.metadata?.userId
        || (session.customer ? undefined : undefined);
      const user = await getUserById(req.session.userId!);
      if (sessionUserId && sessionUserId !== String(req.session.userId)) {
        return res.status(403).json({ message: "Session does not belong to this user" });
      }
      if (user && (user as any).stripeCustomerId && session.customer !== (user as any).stripeCustomerId) {
        return res.status(403).json({ message: "Session customer mismatch" });
      }

      if (session.payment_status === "paid" || session.status === "complete") {
        const planFromMeta = (session.metadata as any)?.plan || "growth";
        const intervalFromMeta = (session.metadata as any)?.interval || "monthly";
        await updateUser(req.session.userId!, {
          subscriptionTier: planFromMeta,
          subscriptionInterval: intervalFromMeta,
          subscriptionExpiresAt: null,
        } as any);
        return res.json({ success: true, tier: planFromMeta });
      }
      return res.json({ success: false, status: session.status });
    } catch (error: any) {
      console.error("Verify session error:", error);
      return res.status(500).json({ message: "Failed to verify session" });
    }
  });

  router.post("/api/subscription/webhook", async (req: Request, res: Response) => {
    try {
      if (!getStripe()) return res.status(503).send("Stripe not configured");
      const sig = req.headers["stripe-signature"];
      const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;

      if (!sig) {
        console.error("Stripe webhook: missing stripe-signature header");
        return res.status(400).send("Missing stripe-signature header");
      }
      if (!webhookSecret) {
        console.error("Stripe webhook: STRIPE_WEBHOOK_SECRET not configured — rejecting request");
        return res.status(400).send("Webhook secret not configured");
      }

      let event: any;
      try {
        event = (await getStripe())!.webhooks.constructEvent(req.rawBody as Buffer, sig as string, webhookSecret);
      } catch (err: any) {
        console.error("Webhook signature verification failed:", err.message);
        trackEvent("system", "WEBHOOK_SIGNATURE_FAILED", { error: err.message }).catch(() => {});
        return res.status(400).send(`Webhook Error: ${err.message}`);
      }

      switch (event.type) {
        case "checkout.session.completed": {
          const session = event.data.object;
          const userId = session.subscription_data?.metadata?.userId || session.metadata?.userId;
          if (userId && session.mode === "subscription") {
            const planMeta = session.subscription_data?.metadata?.plan || session.metadata?.plan || "growth";
            const intervalMeta = session.subscription_data?.metadata?.interval || session.metadata?.interval || "monthly";
            const updateData: Record<string, any> = {
              subscriptionTier: planMeta,
              subscriptionInterval: intervalMeta,
              subscriptionExpiresAt: null,
            };
            if (session.customer) updateData.stripeCustomerId = session.customer as string;
            if (session.subscription) updateData.stripeSubscriptionId = session.subscription as string;
            updateData.subscriptionPlatform = "stripe";
            updateData.subscriptionSyncedAt = new Date();
            if (session.subscription) updateData.stripeSubscriptionStatus = "active";
            // Set subscription_started_at only on first purchase
            await pool.query(
              "UPDATE users SET subscription_started_at = NOW() WHERE id = $1 AND subscription_started_at IS NULL",
              [userId]
            );
            await updateUser(userId, updateData as any);
            trackEvent(userId, AnalyticsEvents.UPGRADE_COMPLETED, { plan: planMeta, interval: intervalMeta }).catch(() => {});
            console.log(`Subscription activated for user ${userId} on plan ${planMeta}`);

            // Sync to RevenueCat: grant promotional entitlement so mobile reflects web purchase
            try {
              const { grantRevenueCatEntitlement } = await import("./revenuecatRouter");
              const user = await getUserById(userId);
              const appUserId = (user as any)?.revenuecatUserId || userId;
              const durationMonths = intervalMeta === "annual" ? 12 : 1;
              await grantRevenueCatEntitlement(appUserId, planMeta, durationMonths);
              await pool.query(
                "UPDATE users SET revenuecat_entitlement = $1, revenuecat_user_id = $2, subscription_synced_at = NOW() WHERE id = $3",
                [planMeta, appUserId, userId]
              );
              console.log(`[Stripe→RC] Granted ${planMeta} entitlement to ${appUserId}`);
            } catch (rcErr: any) {
              console.error("[Stripe→RC] Failed to sync to RevenueCat:", rcErr.message);
              // Non-fatal — DB is source of truth
            }

            // Referral credit: give referrer 1 free month when referred user upgrades
            // Includes fraud protection: 30-day check, same-IP, 6-month cap, email domain flag
            try {
              const newUser = await getUserById(userId);
              const referredBy = (newUser as any)?.referredBy as string | null;
              if (referredBy) {
                const referrerResult = await pool.query(
                  `SELECT id, referral_credits_months, email, signup_ip
                   FROM users WHERE referral_code = $1 LIMIT 1`,
                  [referredBy]
                );
                if (referrerResult.rows.length > 0) {
                  const referrer = referrerResult.rows[0];

                  // ① 30-day paid subscription required before crediting
                  const subStart: Date | null = (newUser as any)?.subscriptionStartedAt
                    ? new Date((newUser as any).subscriptionStartedAt)
                    : null;
                  const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
                  if (!subStart || subStart > thirtyDaysAgo) {
                    console.log(`Referral credit deferred: referred user ${userId} has not been paid for 30 days yet`);
                    // Leave for a future cron to re-evaluate — do not credit now
                  } else {
                    // ② Same-IP fraud detection
                    const referredIp: string | null = (newUser as any)?.signupIp || null;
                    const referrerIp: string | null = referrer.signup_ip || null;
                    if (referredIp && referrerIp && referredIp === referrerIp) {
                      await pool.query(
                        "UPDATE users SET referral_fraud_flagged = true WHERE id = $1",
                        [userId]
                      );
                      trackEvent(userId, "REFERRAL_FRAUD_SUSPECTED", {
                        reason: "same_ip",
                        referrerId: referrer.id,
                        ip: referredIp,
                      }).catch(() => {});
                      console.warn(`Referral fraud suspected (same IP): referrer=${referrer.id}, referred=${userId}`);
                    } else {
                      // ③ Email domain flag (same domain, not gmail/yahoo/hotmail etc.)
                      const GENERIC_DOMAINS = new Set(["gmail.com", "yahoo.com", "hotmail.com", "outlook.com", "icloud.com"]);
                      const referredDomain = ((newUser as any)?.email || "").split("@")[1]?.toLowerCase();
                      const referrerDomain = (referrer.email || "").split("@")[1]?.toLowerCase();
                      if (
                        referredDomain &&
                        referrerDomain &&
                        referredDomain === referrerDomain &&
                        !GENERIC_DOMAINS.has(referredDomain)
                      ) {
                        trackEvent(userId, "REFERRAL_DOMAIN_MATCH_FLAGGED", {
                          domain: referredDomain,
                          referrerId: referrer.id,
                        }).catch(() => {});
                        console.warn(`Referral domain match flagged: both @${referredDomain}`);
                        // Flag but do NOT block — allow credit to proceed
                      }

                      // ④ Cap at 6 credits
                      const currentCredits = referrer.referral_credits_months ?? 0;
                      if (currentCredits >= 6) {
                        trackEvent(referrer.id, "REFERRAL_CAP_REACHED", { totalCredits: currentCredits }).catch(() => {});
                        console.log(`Referral cap reached for user ${referrer.id} (${currentCredits} months already)`);
                      } else {
                        await pool.query(
                          "UPDATE users SET referral_credits_months = referral_credits_months + 1, updated_at = NOW() WHERE id = $1",
                          [referrer.id]
                        );
                        console.log(`Referral credit applied to user ${referrer.id} (now ${currentCredits + 1} months)`);
                      }
                    }
                  }
                }
              }
            } catch (refErr: any) {
              console.error("Referral credit error:", refErr.message);
            }
          }

          // ── Tip payment handling ──────────────────────────────────────────
          if (session.metadata?.type === "tip" && session.metadata?.tipId) {
            const { tipId } = session.metadata;
            try {
              await pool.query(
                `UPDATE tips SET status='paid', paid_at=NOW(), stripe_checkout_session_id=$1 WHERE id=$2`,
                [session.id, tipId]
              );
              // Also update job.tip_amount for quick reference
              await pool.query(
                `UPDATE jobs SET tip_amount = (SELECT amount FROM tips WHERE id=$1) WHERE id = (SELECT job_id FROM tips WHERE id=$1)`,
                [tipId]
              );
              console.log(`Tip paid: ${tipId}`);
            } catch (tipErr: any) {
              console.error("Tip webhook error:", tipErr.message);
            }
          }

          break;
        }
        case "customer.subscription.deleted":
        case "customer.subscription.updated": {
          const subscription = event.data.object;
          const userId = subscription.metadata?.userId;
          if (userId) {
            const isActive = subscription.status === "active" || subscription.status === "trialing";
            const planFromMeta = subscription.metadata?.plan || "growth";
            await updateUser(userId, {
              subscriptionTier: isActive ? planFromMeta : "free",
              subscriptionExpiresAt: isActive ? null : new Date(),
              stripeSubscriptionId: subscription.id,
              stripeSubscriptionStatus: subscription.status,
              subscriptionPlatform: isActive ? "stripe" : null,
              subscriptionSyncedAt: new Date(),
            } as any);
            console.log(`Subscription ${isActive ? "active (" + planFromMeta + ")" : "cancelled"} for user ${userId}`);
          }
          break;
        }
        case "invoice.payment_failed": {
          const invoice = event.data.object as any;
          const stripeCustomerId = invoice.customer as string;
          if (stripeCustomerId) {
            try {
              const userResult = await pool.query(
                "SELECT id, email, name FROM users WHERE stripe_customer_id = $1 LIMIT 1",
                [stripeCustomerId]
              );
              if (userResult.rows.length > 0) {
                const failedUser = userResult.rows[0];
                const { sendEmail, getBusinessSendParams } = await import("../mail");
                const business = await getBusinessByOwner(failedUser.id);
                const sendParams = business ? getBusinessSendParams(business) : null;
                await sendEmail({
                  to: failedUser.email,
                  from: sendParams?.from,
                  subject: "Action needed: Payment issue with your QuotePro subscription",
                  html: `<div style="font-family:sans-serif;max-width:520px;margin:0 auto">
<h2 style="color:#0f172a">Payment failed</h2>
<p>Hi ${failedUser.name || "there"},</p>
<p>We had trouble processing your most recent QuotePro payment. To keep your account active, please update your payment method.</p>
<p><a href="${process.env.EXPO_PUBLIC_DOMAIN || "https://quotepro.ai"}/app/settings" style="background:#2563eb;color:#fff;padding:10px 20px;border-radius:6px;text-decoration:none;font-weight:600">Update payment method</a></p>
<p style="color:#64748b;font-size:0.875rem">If you believe this is an error, reply to this email and we'll help you right away.</p>
</div>`,
                  text: `Hi ${failedUser.name || "there"}, your recent QuotePro payment failed. Please update your payment method at: ${process.env.EXPO_PUBLIC_DOMAIN || "https://quotepro.ai"}/app/settings`,
                });
                console.log(`Payment failed email sent to user ${failedUser.id}`);
              }
            } catch (emailErr: any) {
              console.error("Failed to send payment_failed email:", emailErr.message);
            }
          }
          break;
        }
      }

      return res.json({ received: true });
    } catch (error: any) {
      console.error("Webhook error:", error);
      return res.status(500).json({ message: "Webhook processing failed" });
    }
  });

  // ── Unified subscription status endpoint ──────────────────────────────────
  router.get("/api/subscription/status", requireAuth, async (req: Request, res: Response) => {
    try {
      const userId = req.session.userId!;
      const result = await pool.query(
        `SELECT subscription_tier, subscription_interval, subscription_expires_at,
                stripe_customer_id, stripe_subscription_id, stripe_subscription_status,
                revenuecat_user_id, revenuecat_entitlement,
                subscription_platform, subscription_synced_at,
                trial_started_at, created_at
         FROM users WHERE id = $1 LIMIT 1`,
        [userId]
      );

      if (result.rows.length === 0) return res.status(404).json({ message: "User not found" });

      const u = result.rows[0];
      const tier = (u.subscription_tier || "free") as string;
      const platform = (u.subscription_platform as string | null) ?? null;

      // Derive status
      let status: "active" | "trialing" | "past_due" | "cancelled" = "cancelled";
      if (tier !== "free") {
        if (u.stripe_subscription_status === "past_due") {
          status = "past_due";
        } else {
          status = "active";
        }
      } else {
        // Check trial
        const FREE_TRIAL_DAYS = 14;
        const trialRef = u.trial_started_at || u.created_at;
        const ageMs = trialRef ? Date.now() - new Date(trialRef).getTime() : Infinity;
        if (ageMs < FREE_TRIAL_DAYS * 86_400_000) {
          status = "trialing";
        }
      }

      const isOnTrial = status === "trialing";
      const FREE_TRIAL_DAYS = 14;
      const trialRef = u.trial_started_at || u.created_at;
      const ageMs = trialRef ? Date.now() - new Date(trialRef).getTime() : Infinity;
      const trialDaysRemaining = isOnTrial
        ? Math.max(0, FREE_TRIAL_DAYS - Math.floor(ageMs / 86_400_000))
        : null;

      return res.json({
        tier,
        platform,
        status,
        currentPeriodEnd: u.subscription_expires_at ?? null,
        isOnTrial,
        trialDaysRemaining,
        canManageOnWeb: platform === "stripe" || platform === null,
        canManageOnIOS: platform === "revenuecat",
        stripeCustomerId: u.stripe_customer_id ?? null,
        revenuecatUserId: u.revenuecat_user_id ?? null,
        syncedAt: u.subscription_synced_at ?? null,
      });
    } catch (err: any) {
      console.error("[subscription/status]", err.message);
      return res.status(500).json({ message: "Failed to get subscription status" });
    }
  });

