  router.delete("/api/files/:id", requireAuth, async (req: Request, res: Response) => {
    try {
      const business = await getBusinessByOwner(req.session.userId!);
      if (!business) return res.status(404).json({ message: "Business not found" });
      const [file] = await db
        .select()
        .from(businessFiles)
        .where(and(eq(businessFiles.id, req.params.id), eq(businessFiles.businessId, business.id)));
      if (!file) return res.status(404).json({ message: "File not found" });

      const fs = await import("fs");
      const path = await import("path");
      const filePath = path.join(process.cwd(), file.fileUrl);
      try { fs.unlinkSync(filePath); } catch {}

      await db.delete(businessFiles).where(eq(businessFiles.id, req.params.id));
      return res.json({ message: "Deleted" });
    } catch (err: any) {
      return res.status(500).json({ message: "Failed to delete file" });
    }
  });

  router.post("/api/analytics/events", requireAuth, async (req: Request, res: Response) => {
    try {
      const business = await getBusinessByOwner(req.session.userId!);
      if (!business) return res.status(404).json({ message: "Business not found" });
      const { eventName, properties } = req.body;
      if (!eventName) {
        return res.status(400).json({ message: "eventName is required" });
      }
      const event = await createAnalyticsEvent({
        businessId: business.id,
        eventName,
        properties: properties || {},
      });
      return res.json(event);
    } catch (error: any) {
      console.error("Create analytics event error:", error);
      return res.status(500).json({ message: "Failed to create analytics event" });
    }
  });

// ─── Geocode proxy ────────────────────────────────────────────────────────────

const geocodeCache = new Map<string, { results: any[]; expiresAt: number }>();

const geocodeLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 10,
  keyGenerator: (req: any) => String(req.session?.userId ?? "unknown"),
  standardHeaders: true,
  legacyHeaders: false,
  validate: { xForwardedForHeader: false },
  message: { message: "Too many geocode requests. Try again later." },
});

router.get("/api/geocode/city-suggestions", requireAuth, geocodeLimiter, async (req: Request, res: Response) => {
  try {
    const q = ((req.query.q as string) || "").trim();
    if (q.length < 2) return res.json([]);

    const cacheKey = q.toLowerCase();
    const cached = geocodeCache.get(cacheKey);
    if (cached && cached.expiresAt > Date.now()) return res.json(cached.results);

    const url = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(q)}&format=json&limit=6&featuretype=city&addressdetails=1`;
    const r = await fetch(url, {
      headers: {
        "User-Agent": "QuotePro/1.0 (quotepro.ai)",
        "Accept-Language": "en",
      },
    });

    if (!r.ok) {
      console.error("Nominatim error:", r.status);
      return res.json([]);
    }

    const data: any[] = await r.json();
    const seen = new Set<string>();
    const results: { display: string; city: string; state: string }[] = [];

    for (const d of data) {
      if (!d.address) continue;
      const city = d.address.city || d.address.town || d.address.village || d.name;
      if (!city) continue;
      const state = d.address.state_code || d.address.state || "";
      const display = state ? `${city}, ${state}` : city;
      if (!seen.has(display)) {
        seen.add(display);
        results.push({ display, city, state });
      }
      if (results.length >= 6) break;
    }

    geocodeCache.set(cacheKey, { results, expiresAt: Date.now() + 60 * 60 * 1000 });
    return res.json(results);
  } catch (error: any) {
    console.error("Geocode city-suggestions error:", error);
    return res.json([]);
  }
});

